typedef logic [31:0][63:0] matrix_t [];
matrix_t out = new [2560];
out[0][0][0] = 1'b0;

parameter int D = 2560;
localparam int M = 64;
localparam int N = D / M;
typedef logic [N-1:0][M-1:0] matrix_t [];
matrix_t out = new [D];
int idx = D * 2;
out[idx/D][(idx%D)/M][(idx%D)%M] = 1'b0;

function automatic logic [31:0][63:0] foo();
